// Bank represents a bank with multiple accounts.
// It uses a RWMutex to protect concurrent access to account balances.
type Bank struct {
	accounts map[string]int
	mu       sync.RWMutex
}

// NewBank creates and returns a new Bank instance.
func NewBank() *Bank {
	return &Bank{
		accounts: make(map[string]int),
	}
}

var (
	ErrInsufficientFunds = errors.New("insufficient funds")
	ErrAccountNotFound   = errors.New("account not found")
	ErrInvalidAmount     = errors.New("amount must be positive")
)

// Deposit adds money to an account.
// It acquires a write lock to safely update the account balance.
func (b *Bank) Deposit(accountID string, amount int) error {
	if amount <= 0 {
		return ErrInvalidAmount
	}

	b.mu.Lock()         // Acquire a write lock
	defer b.mu.Unlock() // Release the lock when the function returns

	b.accounts[accountID] += amount
	return nil
}

// Withdraw removes money from an account.
// It acquires a write lock to safely update the account balance.
// It returns an error if the account does not exist,
// the amount is invalid, or there are insufficient funds.
func (b *Bank) Withdraw(accountID string, amount int) error {
	if amount <= 0 {
		return ErrInvalidAmount
	}

	b.mu.Lock()         // Acquire a write lock
	defer b.mu.Unlock() // Release the lock when the function returns

	balance, exists := b.accounts[accountID]
	if !exists {
		return ErrAccountNotFound
	}

	if balance < amount {
		return ErrInsufficientFunds
	}

	b.accounts[accountID] -= amount
	return nil
}

// GetBalance retrieves the current balance of an account.
// It acquires a read lock to safely read the account balance.
func (b *Bank) GetBalance(accountID string) (int, error) {
	b.mu.RLock()         // Acquire a read lock
	defer b.mu.RUnlock() // Release the lock when the function returns

	balance, exists := b.accounts[accountID]
	if !exists {
		return 0, ErrAccountNotFound
	}
	return balance, nil
}

